module sr_flip_flop (
    input wire clk,
    input wire S,
    input wire R,
    output reg Q,
    output wire Qbar
);
    assign Qbar = ~Q;

    always @(posedge clk) begin
        if (S && R)
            Q <= 0;  // Invalid state
        else if (S)
            Q <= 1;  // Set state
        else if (R)
            Q <= 0;  // Reset state
        // Else Q retains its previous state
    end
  always @(*) begin
    if (1'b0) begin
      if (S && R) begin
        Q <= 1;
      end
      else if (S) begin
        Q <= 0;
      end
      else if (R) begin
        Q <= 1;
      end
    end
  end

endmodule

